import React, { useState } from 'react';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:8000';

const WORKFLOWS = [
  { id: 'market_analysis', name: 'Market Analysis', description: 'Brief market summary for a city' },
  { id: 'lead_followup', name: 'Lead Follow-up', description: 'Short follow-up email' },
  { id: 'new_listing', name: 'New Listing', description: 'Property listing description' }
];

function Workflows() {
  const [selectedWorkflow, setSelectedWorkflow] = useState('');
  const [location, setLocation] = useState('');
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!selectedWorkflow) return;

    setLoading(true);
    setResult(null);

    let prompt = '';
    if (selectedWorkflow === 'market_analysis') {
      prompt = `Brief Austin TX real estate market 2025 summary in 2 sentences`;
    } else if (selectedWorkflow === 'lead_followup') {
      prompt = `Write a 2-sentence professional follow-up email`;
    } else {
      prompt = `Write a 2-sentence property listing description`;
    }

    try {
      const response = await fetch(`${API_URL}/ai_chat`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ message: prompt })
      });
      const data = await response.json();
      setResult(data.response || data);
    } catch (error) {
      setResult({ error: error.message });
    }
    setLoading(false);
  }

  return (
    <div style={{ maxWidth: '800px', margin: '0 auto' }}>
      <h2>⚙️ Workflows</h2>

      <form onSubmit={handleSubmit} style={{ 
        background: 'rgba(22,27,34,0.8)', 
        border: '1px solid rgba(139,148,158,0.15)', 
        borderRadius: '16px', 
        padding: '2rem'
      }}>
        <select 
          value={selectedWorkflow} 
          onChange={(e) => setSelectedWorkflow(e.target.value)}
          style={{
            width: '100%',
            padding: '0.875rem',
            background: 'rgba(0,0,0,0.4)',
            border: '1px solid rgba(139,148,158,0.25)',
            borderRadius: '10px',
            color: '#fff',
            marginBottom: '1rem'
          }}
        >
          <option value="">Select Workflow</option>
          {WORKFLOWS.map(w => (
            <option key={w.id} value={w.id}>{w.name}</option>
          ))}
        </select>

        <input 
          type="text"
          value={location}
          onChange={(e) => setLocation(e.target.value)}
          placeholder="Optional details..."
          style={{
            width: '100%',
            padding: '0.875rem',
            background: 'rgba(0,0,0,0.4)',
            border: '1px solid rgba(139,148,158,0.25)',
            borderRadius: '10px',
            color: '#fff',
            marginBottom: '1rem'
          }}
        />

        <button 
          type="submit" 
          disabled={!selectedWorkflow || loading}
          style={{
            background: loading ? '#666' : 'linear-gradient(135deg, #238636, #2ea043)',
            color: 'white',
            border: 'none',
            padding: '0.875rem',
            borderRadius: '10px',
            fontWeight: '600',
            width: '100%',
            cursor: loading ? 'not-allowed' : 'pointer'
          }}
        >
          {loading ? 'Running...' : 'Run Workflow'}
        </button>
      </form>

      {result && (
        <div style={{ 
          background: 'rgba(0,0,0,0.3)', 
          borderRadius: '12px', 
          padding: '1.5rem',
          marginTop: '1.5rem',
          textAlign: 'left'
        }}>
          <pre style={{ whiteSpace: 'pre-wrap', color: '#e6edf3', fontFamily: 'inherit' }}>
            {typeof result === 'string' ? result : JSON.stringify(result, null, 2)}
          </pre>
        </div>
      )}
    </div>
  );
}

export default Workflows;
